sys_script.script:
(function executeRule(current, previous /*null when async*/) {

    var engine = new IncidentEscalationEngine(current.sys_id.toString());

    var slaDueMS     = new GlideDateTime(current.sla_due).getNumericValue();
    var nowMS        = new GlideDateTime().getNumericValue();
    var remainingMin = (slaDueMS - nowMS) / 60000;

    var threshold = parseInt(gs.getProperty('u_escalation.sla_warn_minutes', '30'));

    if (remainingMin <= threshold && remainingMin > 0) {
        gs.info('IncidentEscalationEngine: SLA warning threshold reached for INC ' + current.number);
        engine.escalate('SLA_WARNING');
    } else if (remainingMin <= 0) {
        gs.warn('IncidentEscalationEngine: SLA breached for INC ' + current.number);
        engine.escalate('SLA_BREACH');
    }

})(current, previous);
